    const [activeSessions, setActiveSessions] = useState([]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [statsRes, sessionsRes] = await Promise.all([
                    api.get('/admin/stats'),
                    api.get('/attendance/sessions')
